SELECT a.PRDCT_TIME as 'DATE', ROUND((a.PUMP_PWR_PRDCT*1.1) + (((d.ALL_AVG_PWR+COALESCE (f.SUN_AVG_PWR, 0)) - e.PUMP_AVG_PWR) * 0.9 ), 2) AS PRDCT_PWR, COALESCE(c.all_pwq, 0) AS PWR, CASE WHEN a.PUMP_PWR_PRDCT >= b.peak THEN 'Y' ELSE 'N' END AS 'PEAK_YN' FROM ( SELECT DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') AS PRDCT_TIME, SUM(t.PWR_PRDCT) AS PUMP_PWR_PRDCT FROM TB_CTR_OPT_RST t INNER JOIN ( SELECT PRDCT_TIME, PUMP_GRP, MAX(ANLY_TIME) AS MaxANLY_TIME FROM TB_CTR_OPT_RST GROUP BY PRDCT_TIME, PUMP_GRP ) AS max_times ON t.PRDCT_TIME = max_times.PRDCT_TIME AND t.ANLY_TIME = max_times.MaxANLY_TIME AND t.PUMP_GRP = max_times.PUMP_GRP WHERE t.PRDCT_TIME >= DATE_SUB(NOW(), INTERVAL 6 HOUR) AND t.PRDCT_TIME < DATE_ADD(NOW(), INTERVAL 18 HOUR) GROUP BY DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') ) a LEFT JOIN ( SELECT DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00') as TS, ROUND(AVG(rhi.VALUE*pti.PWI_UNIT_VALUE),2) AS all_pwq FROM TB_RAWDATA rhi, TB_PEAK_TAG_INF pti WHERE rhi.tagname = pti.PWI_TAG AND pti.IS_ALL ='1' and rhi.value > 0 AND rhi.TS >= DATE_SUB(NOW(), INTERVAL 6 HOUR) AND rhi.TS < DATE_ADD(NOW(), INTERVAL 0 HOUR) GROUP BY DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00:00')
) c ON a.PRDCT_TIME = c.TS LEFT JOIN ( SELECT value AS 'peak' FROM TB_PTR_CTR_INF WHERE tag = (SELECT TAG FROM TB_WPP_TAG_CODE WHERE func_typ = 'selectPeakGoal') ) b ON 1=1 LEFT JOIN ( SELECT CONCAT(DATE_FORMAT(DATE, '%Y-%m-%d '), TIME) as TS, AveragePower as 'ALL_AVG_PWR' FROM( SELECT DATE_FORMAT(DATETIME, '%H:00:00') as TIME, MAX(DATE) as DATE, ROUND(AVG(PWR), 2) as AveragePower FROM ( SELECT concat(DATE_FORMAT(ts, '%Y-%m-%d %H') , ':00:00') as DATETIME, DATE_FORMAT(MAX(ts), '%Y-%m-%d') as DATE, SUM(Y) PWR FROM ( SELECT ts, tagname, ROUND(rdh.VALUE*pti.PWI_UNIT_VALUE,2) AS y FROM TB_RAWDATA_HOUR rdh, TB_PEAK_TAG_INF pti WHERE rdh.tagname = pti.PWI_TAG and pti.IS_ALL ='1' AND rdh.VALUE > 0 AND rdh.ts >= DATE_SUB( DATE_SUB(NOW(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_SUB( DATE_SUB(NOW(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) a GROUP BY ts ) a GROUP BY TIME ) aa
) d ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = DATE_FORMAT(d.TS, '%H:%i') LEFT JOIN ( SELECT DATE_FORMAT(DATETIME, '%H:00') as timeOnly, MAX(DATE) as DATE, ROUND(AVG(paa.PUMP_PWR), 2) as PUMP_AVG_PWR FROM ( SELECT concat(DATE_FORMAT(pa.TS, '%Y-%m-%d %H') , ':00:00.000') as DATETIME, DATE_FORMAT(MAX(pa.TS), '%Y-%m-%d') as DATE, SUM(pa.Y) as 'PUMP_PWR' FROM ( SELECT rdh.TS, rdh.TAGNAME, ROUND(rdh.VALUE*pti.PWI_UNIT_VALUE,2) AS Y FROM TB_RAWDATA_HOUR rdh, TB_CTR_PRF_PUMPMST_INF cppi, TB_PEAK_TAG_INF pti where rdh.TAGNAME = cppi.PWI_TAG AND pti.PWQ_TAG = cppi.PWQ_TAG AND rdh.VALUE > 0 AND rdh.ts >= DATE_SUB( DATE_SUB(NOW(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_SUB( DATE_SUB(NOW(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) pa GROUP BY TS ) paa GROUP BY timeOnly ) e ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = e.timeOnly LEFT JOIN ( SELECT TIME as timeOnly, IFNULL(AveragePower, 0) as SUN_AVG_PWR FROM ( SELECT DATE_FORMAT(DATETIME, '%H:00') as TIME, MAX(DATE) as DATE, ROUND(AVG(PWR), 2) as AveragePower FROM ( SELECT concat(DATE_FORMAT(ts, '%Y-%m-%d %H') , ':00') as DATETIME, DATE_FORMAT(MAX(ts), '%Y-%m-%d') as DATE, SUM(Y) PWR FROM ( SELECT ts, tagname, ROUND(rdh.VALUE * pti.PWI_UNIT_VALUE, 2) AS y FROM TB_RAWDATA_HOUR rdh, TB_PEAK_TAG_INF pti WHERE rdh.tagname = pti.PWI_TAG and pti.CLSFC = '태양광' AND rdh.ts >= DATE_SUB( DATE_SUB(NOW(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_SUB( DATE_SUB(NOW(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) a GROUP BY ts ) a GROUP BY TIME ) a )f ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = f.timeOnly
ORDER BY a.PRDCT_TIME

SELECT a.PRDCT_TIME as 'DATE', ROUND(a.PUMP_PWR_PRDCT, 2) AS PRDCT_PWR, COALESCE(c.all_pwq, 0) AS PWR, CASE WHEN a.PUMP_PWR_PRDCT >= b.peak THEN 'Y' ELSE 'N' END AS 'PEAK_YN' FROM ( SELECT DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') AS PRDCT_TIME, SUM(t.PWR_PRDCT) AS PUMP_PWR_PRDCT FROM TB_CTR_OPT_RST t INNER JOIN ( SELECT PRDCT_TIME, PUMP_GRP, MAX(ANLY_TIME) AS MaxANLY_TIME FROM TB_CTR_OPT_RST WHERE PUMP_GRP = 0 GROUP BY PRDCT_TIME, PUMP_GRP ) AS max_times ON t.PRDCT_TIME = max_times.PRDCT_TIME AND t.ANLY_TIME = max_times.MaxANLY_TIME AND t.PUMP_GRP = max_times.PUMP_GRP WHERE t.PRDCT_TIME >= DATE_SUB(NOW(), INTERVAL 6 HOUR) AND t.PRDCT_TIME < DATE_ADD(NOW(), INTERVAL 18 HOUR) AND t.PUMP_GRP = 0 GROUP BY DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') ) a LEFT JOIN ( SELECT DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00') as TS, ROUND(AVG(rhi.VALUE*pti.PWI_UNIT_VALUE),2) AS all_pwq FROM TB_RAWDATA rhi, TB_PEAK_TAG_INF pti WHERE rhi.tagname = pti.PWI_TAG AND pti.IS_ALL ='1' and rhi.value > 0 AND rhi.TS >= DATE_SUB(NOW(), INTERVAL 6 HOUR) AND rhi.TS < DATE_ADD(NOW(), INTERVAL 0 HOUR) GROUP BY DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00:00')
) c ON a.PRDCT_TIME = c.TS LEFT JOIN ( SELECT value AS 'peak' FROM TB_PTR_CTR_INF WHERE tag = (SELECT TAG FROM TB_WPP_TAG_CODE WHERE func_typ = 'selectPeakGoal') ) b ON 1=1
ORDER BY a.PRDCT_TIME

SELECT a.PRDCT_TIME as 'DATE', ROUND(d.ALL_AVG_PWR, 2) AS PRDCT_PWR, ROUND(COALESCE(c.all_pwq, 0),2) AS PWR, PEAK, CASE WHEN a.PUMP_PWR_PRDCT >= b.PEAK THEN 'Y' ELSE 'N' END AS 'PEAK_YN' FROM ( SELECT DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') AS PRDCT_TIME, SUM(t.PWR_PRDCT) AS PUMP_PWR_PRDCT FROM TB_CTR_OPT_RST t INNER JOIN ( SELECT PRDCT_TIME, PUMP_GRP, MAX(ANLY_TIME) AS MaxANLY_TIME FROM TB_CTR_OPT_RST GROUP BY PRDCT_TIME, PUMP_GRP ) AS max_times ON t.PRDCT_TIME = max_times.PRDCT_TIME AND t.ANLY_TIME = max_times.MaxANLY_TIME AND t.PUMP_GRP = max_times.PUMP_GRP WHERE t.PRDCT_TIME >= DATE_SUB(#{nowDate}, INTERVAL 6 HOUR) AND t.PRDCT_TIME < DATE_ADD(#{nowDate}, INTERVAL 18 HOUR) GROUP BY DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') ) a LEFT JOIN ( SELECT DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00') as TS, ROUND(AVG(rhi.VALUE*pti.PWI_UNIT_VALUE),2) AS all_pwq FROM TB_RAWDATA rhi, TB_PEAK_TAG_INF pti WHERE rhi.tagname = pti.PWI_TAG AND pti.IS_ALL ='1' and rhi.value > 0 AND rhi.TS >= DATE_SUB(#{nowDate}, INTERVAL 6 HOUR) AND rhi.TS <= DATE_ADD(#{nowDate}, INTERVAL 1 MINUTE) GROUP BY DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00:00')
) c ON a.PRDCT_TIME = c.TS LEFT JOIN ( SELECT value AS 'PEAK' FROM TB_PTR_CTR_INF WHERE tag = (SELECT TAG FROM TB_WPP_TAG_CODE WHERE func_typ = 'selectPeakGoal') ) b ON 1=1 LEFT JOIN ( SELECT CONCAT(DATE_FORMAT(DATE, '%Y-%m-%d '), TIME) as TS, AveragePower as 'ALL_AVG_PWR' FROM( SELECT DATE_FORMAT(DATETIME, '%H:00:00') as TIME, MAX(DATE) as DATE, ROUND(AVG(PWR), 2) as AveragePower FROM ( SELECT concat(DATE_FORMAT(ts, '%Y-%m-%d %H') , ':00:00') as DATETIME, DATE_FORMAT(MAX(ts), '%Y-%m-%d') as DATE, SUM(Y) PWR FROM ( SELECT ts, tagname, ROUND(rdh.VALUE*pti.PWI_UNIT_VALUE,2) AS y FROM TB_RAWDATA_HOUR rdh, TB_PEAK_TAG_INF pti WHERE rdh.tagname = pti.PWI_TAG and pti.IS_ALL ='1' AND rdh.VALUE > 0 AND rdh.ts >= DATE_SUB( DATE_SUB(#{nowDate}, INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_ADD( DATE_SUB(#{nowDate}, INTERVAL 1 DAY), INTERVAL 18 HOUR) ) a GROUP BY ts ) a GROUP BY TIME ) aa
) d ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = DATE_FORMAT(d.TS, '%H:%i')
ORDER BY a.PRDCT_TIME

SELECT a.PRDCT_TIME as 'DATE', ROUND(d.ALL_AVG_PWR, 2) AS PRDCT_PWR, ROUND(COALESCE(c.all_pwq, 0),2) AS PWR, PEAK, CASE WHEN a.PUMP_PWR_PRDCT >= b.PEAK THEN 'Y' ELSE 'N' END AS 'PEAK_YN' FROM ( SELECT DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') AS PRDCT_TIME, SUM(t.PWR_PRDCT) AS PUMP_PWR_PRDCT FROM TB_CTR_OPT_RST t INNER JOIN ( SELECT PRDCT_TIME, PUMP_GRP, MAX(ANLY_TIME) AS MaxANLY_TIME FROM TB_CTR_OPT_RST GROUP BY PRDCT_TIME, PUMP_GRP ) AS max_times ON t.PRDCT_TIME = max_times.PRDCT_TIME AND t.ANLY_TIME = max_times.MaxANLY_TIME AND t.PUMP_GRP = max_times.PUMP_GRP WHERE t.PRDCT_TIME >= DATE_SUB(now(), INTERVAL 6 HOUR) AND t.PRDCT_TIME < DATE_ADD(now(), INTERVAL 18 HOUR) GROUP BY DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') ) a LEFT JOIN ( SELECT DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00') as TS, ROUND(AVG(rhi.VALUE*pti.PWI_UNIT_VALUE),2) AS all_pwq FROM TB_RAWDATA rhi, TB_PEAK_TAG_INF pti WHERE rhi.tagname = pti.PWI_TAG AND pti.IS_ALL ='1' and rhi.value > 0 AND rhi.TS >= DATE_SUB(now(), INTERVAL 6 HOUR) AND rhi.TS <= DATE_ADD(now(), INTERVAL 1 MINUTE) GROUP BY DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00:00')
) c ON a.PRDCT_TIME = c.TS LEFT JOIN ( SELECT value AS 'PEAK' FROM TB_PTR_CTR_INF WHERE tag = (SELECT TAG FROM TB_WPP_TAG_CODE WHERE func_typ = 'selectPeakGoal') ) b ON 1=1 LEFT JOIN ( SELECT CONCAT(DATE_FORMAT(DATE, '%Y-%m-%d '), TIME) as TS, AveragePower as 'ALL_AVG_PWR' FROM( SELECT DATE_FORMAT(DATETIME, '%H:00:00') as TIME, MAX(DATE) as DATE, ROUND(AVG(PWR), 2) as AveragePower FROM ( SELECT concat(DATE_FORMAT(ts, '%Y-%m-%d %H') , ':00:00') as DATETIME, DATE_FORMAT(MAX(ts), '%Y-%m-%d') as DATE, SUM(Y) PWR FROM ( SELECT ts, tagname, ROUND(rdh.VALUE*pti.PWI_UNIT_VALUE,2) AS y FROM TB_RAWDATA_HOUR rdh, TB_PEAK_TAG_INF pti WHERE rdh.tagname = pti.PWI_TAG and pti.IS_ALL ='1' AND rdh.VALUE > 0 AND rdh.ts >= DATE_SUB( DATE_SUB(now(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_ADD( DATE_SUB(now(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) a GROUP BY ts ) a GROUP BY TIME ) aa
) d ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = DATE_FORMAT(d.TS, '%H:%i')
ORDER BY a.PRDCT_TIME

SELECT a.PRDCT_TIME as 'DATE', CASE WHEN c.all_pwq > 0 THEN ROUND(a.PUMP_PWR_PRDCT, 2) ELSE ROUND(((d.ALL_AVG_PWR-a.PUMP_PWR_PRDCT)*0.98) +a.PUMP_PWR_PRDCT ,2) END AS PRDCT_PWR, ROUND(COALESCE(c.all_pwq, 0),2) AS PWR, PEAK, CASE WHEN a.PUMP_PWR_PRDCT >= b.PEAK THEN 'Y' ELSE 'N' END AS 'PEAK_YN' FROM ( WITH RankedResults AS ( SELECT t.PRDCT_TIME, t.PUMP_GRP, t.PWR_PRDCT, t.RGSTR_TIME, t.PRDCT_TIME_DIFF, ROW_NUMBER() OVER (PARTITION BY t.PRDCT_TIME, t.PUMP_GRP ORDER BY t.PRDCT_TIME_DIFF ASC) AS rn FROM TB_CTR_OPT_RST t INNER JOIN ( SELECT PRDCT_TIME, PUMP_GRP, MAX(RGSTR_TIME) AS MaxANLY_TIME FROM TB_CTR_OPT_RST WHERE PUMP_GRP = 0 AND FLAG = 2 GROUP BY PRDCT_TIME, PUMP_GRP ) AS max_times ON t.PRDCT_TIME = max_times.PRDCT_TIME AND t.RGSTR_TIME = max_times.MaxANLY_TIME AND t.PUMP_GRP = max_times.PUMP_GRP WHERE t.PRDCT_TIME >= DATE_SUB(now(), INTERVAL 6 HOUR) AND t.PUMP_GRP = 0 AND t.PRDCT_TIME < DATE_ADD(NOW(), INTERVAL 18 HOUR) ) SELECT DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') AS PRDCT_TIME, ROUND(t.PWR_PRDCT, 2) AS PUMP_PWR_PRDCT FROM RankedResults t WHERE t.rn = 1 GROUP BY DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') ) a LEFT JOIN ( SELECT DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00') as TS, ROUND(SUM(rhi.VALUE*pti.PWQ_UNIT_VALUE),2) AS all_pwq FROM TB_RAWDATA_HOUR_INGRT rhi, TB_PEAK_TAG_INF pti WHERE rhi.tagname = pti.PWQ_TAG AND pti.IS_ALL ='1' and rhi.value > 0 AND rhi.TS >= DATE_SUB(now(), INTERVAL 6 HOUR) AND rhi.TS <= DATE_ADD(now(), INTERVAL 1 MINUTE) GROUP BY DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00:00')
) c ON a.PRDCT_TIME = c.TS LEFT JOIN ( SELECT value AS 'PEAK' FROM TB_PTR_CTR_INF WHERE tag = (SELECT TAG FROM TB_WPP_TAG_CODE WHERE func_typ = 'selectPeakGoal') ) b ON 1=1 LEFT JOIN ( SELECT CONCAT(DATE_FORMAT(DATE, '%Y-%m-%d '), TIME) as TS, AveragePower as 'ALL_AVG_PWR' FROM( SELECT DATE_FORMAT(DATETIME, '%H:00:00') as TIME, MAX(DATE) as DATE, ROUND(AVG(PWR), 2) as AveragePower FROM ( SELECT concat(DATE_FORMAT(ts, '%Y-%m-%d %H') , ':00:00') as DATETIME, DATE_FORMAT(MAX(ts), '%Y-%m-%d') as DATE, SUM(Y) PWR FROM ( SELECT ts, tagname, ROUND(rdh.VALUE*pti.PWI_UNIT_VALUE,2) AS y FROM TB_RAWDATA_HOUR rdh, TB_PEAK_TAG_INF pti WHERE rdh.tagname = pti.PWI_TAG and pti.IS_ALL ='1' AND rdh.VALUE > 0 AND rdh.ts >= DATE_SUB( DATE_SUB(now(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_ADD( DATE_SUB(now(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) a GROUP BY ts ) a GROUP BY TIME ) aa
) d ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = DATE_FORMAT(d.TS, '%H:%i')
ORDER BY a.PRDCT_TIME

SELECT a.PRDCT_TIME as 'DATE', CASE WHEN c.all_pwq > 0 THEN ROUND(a.PUMP_PWR_PRDCT, 2) ELSE ROUND(((d.ALL_AVG_PWR-a.PUMP_PWR_PRDCT)*0.98) +a.PUMP_PWR_PRDCT ,2) END AS PRDCT_PWR, ROUND(COALESCE(c.all_pwq, 0),2) AS PWR, PEAK, CASE WHEN a.PUMP_PWR_PRDCT >= b.PEAK THEN 'Y' ELSE 'N' END AS 'PEAK_YN' FROM ( WITH RankedResults AS ( SELECT t.PRDCT_TIME, t.PUMP_GRP, t.PWR_PRDCT, t.RGSTR_TIME, t.PRDCT_TIME_DIFF, ROW_NUMBER() OVER (PARTITION BY t.PRDCT_TIME, t.PUMP_GRP ORDER BY t.PRDCT_TIME_DIFF ASC) AS rn FROM TB_CTR_OPT_RST t INNER JOIN ( SELECT PRDCT_TIME, PUMP_GRP, MAX(RGSTR_TIME) AS MaxANLY_TIME FROM TB_CTR_OPT_RST WHERE PUMP_GRP = 0 AND FLAG = 2 GROUP BY PRDCT_TIME, PUMP_GRP ) AS max_times ON t.PRDCT_TIME = max_times.PRDCT_TIME AND t.RGSTR_TIME = max_times.MaxANLY_TIME AND t.PUMP_GRP = max_times.PUMP_GRP WHERE t.PRDCT_TIME >= DATE_SUB(now(), INTERVAL 6 HOUR) AND t.PUMP_GRP = 0 AND t.PRDCT_TIME < DATE_ADD(NOW(), INTERVAL 18 HOUR) ) SELECT DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') AS PRDCT_TIME, ROUND(t.PWR_PRDCT, 2) AS PUMP_PWR_PRDCT FROM RankedResults t WHERE t.rn = 1 GROUP BY DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') ) a LEFT JOIN ( SELECT DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00') as TS, ROUND(AVG(rhi.VALUE*pti.PWI_UNIT_VALUE),2) AS all_pwq FROM TB_RAWDATA rhi, TB_PEAK_TAG_INF pti WHERE rhi.tagname = pti.PWI_TAG AND pti.IS_ALL ='1' and rhi.value > 0 AND rhi.TS >= DATE_SUB(now(), INTERVAL 6 HOUR) AND rhi.TS <= DATE_ADD(now(), INTERVAL 1 MINUTE) GROUP BY DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00:00')
) c ON a.PRDCT_TIME = c.TS LEFT JOIN ( SELECT value AS 'PEAK' FROM TB_PTR_CTR_INF WHERE tag = (SELECT TAG FROM TB_WPP_TAG_CODE WHERE func_typ = 'selectPeakGoal') ) b ON 1=1 LEFT JOIN ( SELECT CONCAT(DATE_FORMAT(DATE, '%Y-%m-%d '), TIME) as TS, AveragePower as 'ALL_AVG_PWR' FROM( SELECT DATE_FORMAT(DATETIME, '%H:00:00') as TIME, MAX(DATE) as DATE, ROUND(AVG(PWR), 2) as AveragePower FROM ( SELECT concat(DATE_FORMAT(ts, '%Y-%m-%d %H') , ':00:00') as DATETIME, DATE_FORMAT(MAX(ts), '%Y-%m-%d') as DATE, SUM(Y) PWR FROM ( SELECT ts, tagname, ROUND(rdh.VALUE*pti.PWI_UNIT_VALUE,2) AS y FROM TB_RAWDATA_HOUR rdh, TB_PEAK_TAG_INF pti WHERE rdh.tagname = pti.PWI_TAG and pti.IS_ALL ='1' AND rdh.VALUE > 0 AND rdh.ts >= DATE_SUB( DATE_SUB(now(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_ADD( DATE_SUB(now(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) a GROUP BY ts ) a GROUP BY TIME ) aa
) d ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = DATE_FORMAT(d.TS, '%H:%i')
ORDER BY a.PRDCT_TIME

SELECT a.PRDCT_TIME as 'DATE', ROUND((a.PUMP_PWR_PRDCT*1.1) + (((d.ALL_AVG_PWR+COALESCE (f.SUN_AVG_PWR, 0)) - e.PUMP_AVG_PWR)* 0.9 ) - COALESCE (f.SUN_AVG_PWR, 0), 2) AS PRDCT_PWR, COALESCE(c.all_pwq, 0) AS PWR, CASE WHEN a.PUMP_PWR_PRDCT = b.peak THEN 'Y' ELSE 'N' END AS 'PEAK_YN' FROM ( SELECT DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') AS PRDCT_TIME, SUM(t.PWR_PRDCT) AS PUMP_PWR_PRDCT FROM TB_CTR_OPT_RST t INNER JOIN ( SELECT PRDCT_TIME, PUMP_GRP, MAX(ANLY_TIME) AS MaxANLY_TIME FROM TB_CTR_OPT_RST GROUP BY PRDCT_TIME, PUMP_GRP ) AS max_times ON t.PRDCT_TIME = max_times.PRDCT_TIME AND t.ANLY_TIME = max_times.MaxANLY_TIME AND t.PUMP_GRP = max_times.PUMP_GRP WHERE t.PRDCT_TIME >= DATE_SUB(NOW(), INTERVAL 6 HOUR) AND t.PRDCT_TIME <= DATE_ADD(NOW(), INTERVAL 18 HOUR) GROUP BY DATE_FORMAT(t.PRDCT_TIME, '%Y-%m-%d %H:%i') ) a LEFT JOIN ( SELECT DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00') as TS, ROUND(AVG(rhi.VALUE * pti.PWI_UNIT_VALUE),2) AS all_pwq FROM TB_RAWDATA rhi, TB_PEAK_TAG_INF pti WHERE rhi.tagname = pti.PWI_TAG AND pti.IS_ALL ='1' and rhi.value != 0 AND rhi.TS >= DATE_SUB(NOW(), INTERVAL 6 HOUR) AND rhi.TS <= DATE_ADD(NOW(), INTERVAL 0 HOUR) GROUP BY DATE_FORMAT(rhi.TS, '%Y-%m-%d %H:00:00')
) c ON a.PRDCT_TIME = c.TS LEFT JOIN ( SELECT value AS 'peak' FROM TB_PTR_CTR_INF WHERE tag = (SELECT TAG FROM TB_WPP_TAG_CODE WHERE func_typ = 'selectPeakGoal') ) b ON 1=1 LEFT JOIN ( SELECT CONCAT(DATE_FORMAT(DATE, '%Y-%m-%d '), TIME) as TS, AveragePower as 'ALL_AVG_PWR' FROM( SELECT DATE_FORMAT(DATETIME, '%H:00:00') as TIME, MAX(DATE) as DATE, ROUND(AVG(PWR), 2) as AveragePower FROM ( SELECT concat(DATE_FORMAT(ts, '%Y-%m-%d %H') , ':00:00') as DATETIME, DATE_FORMAT(MAX(ts), '%Y-%m-%d') as DATE, SUM(Y) PWR FROM ( SELECT ts, tagname, ROUND(rdh.VALUE * pti.PWI_UNIT_VALUE,2) AS y FROM TB_RAWDATA_HOUR rdh, TB_PEAK_TAG_INF pti WHERE rdh.tagname = pti.PWI_TAG and pti.IS_ALL ='1' AND rdh.VALUE != 0 AND rdh.ts >= DATE_SUB( DATE_SUB(NOW(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_SUB( DATE_SUB(NOW(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) a GROUP BY ts ) a GROUP BY TIME ) aa
) d ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = DATE_FORMAT(d.TS, '%H:%i') LEFT JOIN ( SELECT DATE_FORMAT(DATETIME, '%H:00') as timeOnly, MAX(DATE) as DATE, ROUND(AVG(paa.PUMP_PWR), 2) as PUMP_AVG_PWR FROM ( SELECT concat(DATE_FORMAT(pa.TS, '%Y-%m-%d %H') , ':00:00.000') as DATETIME, DATE_FORMAT(MAX(pa.TS), '%Y-%m-%d') as DATE, SUM(pa.Y) as 'PUMP_PWR' FROM ( SELECT rdh.TS, rdh.TAGNAME, ROUND(rdh.VALUE * pti.PWI_UNIT_VALUE,2) AS Y FROM TB_RAWDATA_HOUR rdh, TB_CTR_PRF_PUMPMST_INF cppi, TB_PEAK_TAG_INF pti where rdh.TAGNAME = cppi.PWI_TAG AND pti.PWQ_TAG = cppi.PWQ_TAG AND rdh.VALUE != 0 AND rdh.ts >= DATE_SUB( DATE_SUB(NOW(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_SUB( DATE_SUB(NOW(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) pa GROUP BY TS ) paa GROUP BY timeOnly ) e ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = e.timeOnly LEFT JOIN ( SELECT TIME as timeOnly, IFNULL(AveragePower, 0) as SUN_AVG_PWR FROM ( SELECT DATE_FORMAT(DATETIME, '%H:00') as TIME, MAX(DATE) as DATE, ROUND(AVG(PWR), 2) as AveragePower FROM ( SELECT concat(DATE_FORMAT(ts, '%Y-%m-%d %H') , ':00') as DATETIME, DATE_FORMAT(MAX(ts), '%Y-%m-%d') as DATE, SUM(Y) PWR FROM ( SELECT ts, tagname, ROUND(rdh.VALUE * pti.PWI_UNIT_VALUE, 2) AS y FROM TB_RAWDATA_HOUR rdh, TB_PEAK_TAG_INF pti WHERE rdh.tagname = pti.PWI_TAG and pti.CLSFC = '태양광' AND rdh.ts >= DATE_SUB( DATE_SUB(NOW(), INTERVAL 15 DAY), INTERVAL 6 HOUR) AND rdh.ts <= DATE_SUB( DATE_SUB(NOW(), INTERVAL 1 DAY), INTERVAL 18 HOUR) ) a GROUP BY ts ) a GROUP BY TIME ) a )f ON DATE_FORMAT(a.PRDCT_TIME, '%H:%i') = f.timeOnly
ORDER BY a.PRDCT_TIME

SELECT DATE_FORMAT(a.DATE,'%Y-%m-%d %H:%i') DATE, b.PRDCT_PWR, IFNULL(b.PEAK_YN,0) PEAK_YN, c.GNRTD_PWR FROM( SELECT DATE(#{date}) + INTERVAL (a.h) HOUR AS DATE FROM ( WITH RECURSIVE cte AS ( SELECT 0 AS h UNION ALL SELECT h+1 FROM cte WHERE h <23 ) SELECT * FROM cte) a ) a LEFT JOIN (
SELECT c.CNFRM_TIME, FORMAT (c.PRDCT_PWR,0) PRDCT_PWR, case when (NOW() > c.cnfrm_time then '0' else PEAK_YN END PEAK_YN FROM TB_PEAK_PWR_PRDCT_RST c INNER JOIN ( SELECT CNFRM_TIME, MAX(ANLY_TIME) AS MaxANLY_TIME FROM TB_PEAK_PWR_PRDCT_RST WHERE CNFRM_TIME >= CONCAT(#{date}, ' 00:00:00') AND CNFRM_TIME <= CONCAT(#{date}, ' 23:59:59') GROUP BY CNFRM_TIME ) b ON c.CNFRM_TIME = b.CNFRM_TIME AND c.ANLY_TIME = b.MaxANLY_TIME ORDER BY c.CNFRM_TIME
) b ON a.DATE = b.CNFRM_TIME LEFT JOIN ( SELECT CNFRM_TIME, FORMAT (GNRTD_PWR,0) GNRTD_PWR FROM TB_PEAK_GNRTD_RST WHERE CNFRM_TIME >= CONCAT(#{date}, ' 00:00:00') AND CNFRM_TIME <= CONCAT(#{date}, ' 23:59:59') ) c ON a.DATE = c.CNFRM_TIME ORDER BY date

SELECT TNK_GRP_IDX, TNK_IDX, TNK_GRP_NM, TNK_NM, group_concat(IN_FO_TAG) as 'IN_FO_TAG', group_concat((select value FROM TB_RAWDATA WHERE tagname = IN_FO_TAG AND ts = (select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) ) ) 'IN_FO', group_concat(OUT_FO_TAG) 'OUT_FO_TAG', group_concat((select value FROM TB_RAWDATA WHERE tagname = OUT_FO_TAG AND ts = (select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) ) ) 'OUT_FO', group_concat(IN_FC_TAG) as 'IN_FC_TAG', group_concat((select value FROM TB_RAWDATA WHERE tagname = IN_FC_TAG AND ts = (select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) )) 'IN_FC', group_concat(OUT_FC_TAG) as 'OUT_FC_TAG', group_concat((select value FROM TB_RAWDATA WHERE tagname = OUT_FC_TAG AND ts = (select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) )) 'OUT_FC', group_concat(IN_POI_TAG) as 'IN_POI_TAG', group_concat((select value FROM TB_RAWDATA WHERE tagname = IN_POI_TAG AND ts = (select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) )) 'IN_POI', group_concat(OUT_POI_TAG) 'OUT_POI_TAG', group_concat((select value FROM TB_RAWDATA WHERE tagname = OUT_POI_TAG AND ts = (select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) )) 'OUT_POI', LEI_TAG, (select value FROM TB_RAWDATA WHERE tagname = LEI_TAG AND ts = (select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) ) '수위', IN_FLW_TAG, (select value FROM TB_RAWDATA WHERE tagname = IN_FLW_TAG AND ts =(select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) ) '유입유량', OUT_FLW_TAG, (select value FROM TB_RAWDATA WHERE tagname = OUT_FLW_TAG AND ts = (select DATE_FORMAT(max(ts),'%Y-%m-%d %H:%i:00') from TB_RAWDATA) ) '유출유량', DMD_PRI '최소요구관압', LWL_LIM '운영수위하한', HWL_LIM '운영수위 상한', MIN_LOAD_LWL '경부하운영수위하한', MAX_LOAD_LWL '경부하운영수위상한', VLM '수저체적', LWL '수조저수위', HWL '수조고수위' FROM TB_TNK_GRP_INF WHERE USE_YN = '1' AND TNK_TYP='1'
AND PUMP_GRP = #{pump_grp}
GROUP BY lei_tag ORDER BY TNK_GRP_IDX,TNK_IDX,DMD_PRI desc

WITH RankedPumps AS ( SELECT COALESCE(cpi.OPT_IDX, cpr.OPT_IDX) as OPT_IDX, COALESCE(cpi.PUMP_GRP, cpr.PUMP_GRP ) as PUMP_GRP, cppi.PUMP_GRP_IDX as PUMP_GRP_IDX, COALESCE(cpi.PUMP_IDX, cpr.PUMP_IDX ) as PUMP_IDX, cppi.PUMP_GRP_NM, cppi.PUMP_NM, cppi.PUMP_TYP as PUMP_TYP, IFNULL(COALESCE(cpi.FREQ, cpr.FREQ), 0) as FREQ, ROUND(IFNULL( COALESCE(cpi.TUBE_PRSR_PRDCT , cpr.TUBE_PRSR_PRDCT) , 0),2) as TUBE_PRSR_PRDCT, cppi.CTR_AUTO_TAG, cppi.CTR_AUTO_STOP_TAG, cppi.CTR_AUTO_FREQ_TAG, DATE_FORMAT(COALESCE(cpi.RGSTR_TIME, cpr.RGSTR_TIME), '%Y-%m-%d %H:%i') AS PRDCT_TIME , CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN "On" ELSE "Off" END AS PUMP_YN, CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN "On" ELSE "Off" END as value, CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN 0 ELSE 1 END as PUMP_YN_VALUE, CASE WHEN cpi.OPT_IDX is not null THEN 1 ELSE 0 END as FLAG, COALESCE(cpi.RATE_CTGRY, '') as RATE_CTGRY, COALESCE(cpi.FLOW_CTR, '') as FLOW_CTR, ROW_NUMBER() OVER (PARTITION BY COALESCE(cpi.PUMP_IDX, cpr.PUMP_IDX ) ORDER BY COALESCE(cpi.RGSTR_TIME, cpr.RGSTR_TIME) DESC) as rn FROM TB_CTR_PUMPYN_RST cpr LEFT JOIN TB_CTR_PUMPYN_INQUIRY cpi on cpr.OPT_IDX = cpr.OPT_IDX AND cpi.RGSTR_TIME >= DATE_SUB(NOW(), INTERVAL 5 MINUTE) AND cpr.PUMP_IDX = cpi.PUMP_IDX JOIN TB_CTR_PRF_PUMPMST_INF cppi ON cpr.PUMP_IDX = cppi.PUMP_IDX
and cppi.PUMP_GRP = #{pump_grp}
WHERE cpr.PRDCT_TIME_DIFF = 5 AND cpr.FLAG = 0 AND cpr.RGSTR_TIME >= DATE_SUB(NOW(), INTERVAL 5 MINUTE) ) SELECT * FROM RankedPumps WHERE rn = 1 ORDER BY PRDCT_TIME DESC, PUMP_IDX ASC;


select
DATE_FORMAT(PRDCT_TIME, '%m-%d %H:%i') AS  PRDCT_TIME ,
PWR_PRDCT
from
TB_CTR_OPT_RST
where
DATE_FORMAT(PRDCT_TIME, '%m-%d %H:%i') = #{DATE_TIME}
AND RGSTR_TIME = (
SELECT MAX(RGSTR_TIME) FROM TB_CTR_OPT_RST where DATE_FORMAT(PRDCT_TIME, '%m-%d %H:%i') = #{DATE_TIME} and PUMP_GRP= #{pump_grp}
) and PUMP_GRP= #{pump_grp}


select
DATE_FORMAT(MIN(PRDCT_TIME), '%y-%m-%d %H:%i') AS  PRDCT_TIME ,
PRDCT_MEAN,
PWR_PRDCT,
TUBE_PRSR_PRDCT
from
TB_CTR_OPT_RST
where RGSTR_TIME = (
SELECT MAX(RGSTR_TIME) FROM TB_CTR_OPT_RST where PUMP_GRP= #{pump_grp}
) and PUMP_GRP= #{pump_grp}


select
DATE_FORMAT(PRDCT_TIME, '%y-%m-%d %H:%i') AS  PRDCT_TIME ,
PRDCT_MEAN,
ROUND(PWR_PRDCT * 1.1 ,2) as 'PWR_PRDCT',
TUBE_PRSR_PRDCT
from
TB_CTR_OPT_RST
where RGSTR_TIME = (
SELECT MAX(RGSTR_TIME) FROM TB_CTR_OPT_RST where PUMP_GRP= #{pump_grp}
) and PUMP_GRP= #{pump_grp}

SELECT tr.TS, tr.TAGNAME, tr.VALUE as value, tcppi.PUMP_IDX, tcppi.PUMP_GRP_NM, tcppi.PUMP_NM FROM TB_RAWDATA tr, TB_CTR_PRF_PUMPMST_INF tcppi WHERE tr.TAGNAME = tcppi.PMB_TAG
and tcppi.PUMP_GRP = #{pump_grp}
AND tr.TS = (SELECT MAX(ts) from TB_RAWDATA where TS >= DATE_SUB(NOW(), INTERVAL 10 MINUTE)) order by tcppi.PUMP_IDX

SELECT cppi.PUMP_IDX, cppi.PUMP_GRP, cppi.PUMP_GRP_NM, cppi.PUMP_NM, rd_pmb.TAGNAME AS PMB_TAGNAME, rd_spi.TAGNAME AS SPI_TAGNAME, MAX(rd_pmb.ts) AS PMB_TS, MAX(rd_spi.ts) AS SPI_TS, rd_pmb.value as PMB_VALUE, IFNULL(rd_spi.value, 0.0) as SPI_VALUE, CASE WHEN rd_pmb.value = 1 THEN "On" ELSE "Off" END AS PUMP_YN, IFNULL(rd_spi.value, 0.0) as 'FREQ' FROM TB_CTR_PRF_PUMPMST_INF cppi LEFT JOIN TB_RAWDATA rd_pmb ON cppi.PMB_TAG = rd_pmb.TAGNAME AND rd_pmb.TS > DATE_SUB(NOW(), INTERVAL 10 MINUTE) AND rd_pmb.TS <= DATE_ADD(NOW(), INTERVAL 10 MINUTE) LEFT JOIN TB_RAWDATA rd_spi ON cppi.SPI_TAG = rd_spi.TAGNAME AND rd_spi.TS > DATE_SUB(NOW(), INTERVAL 10 MINUTE) AND rd_spi.TS <= DATE_ADD(NOW(), INTERVAL 10 MINUTE) WHERE cppi.USE_YN = 1
and cppi.PUMP_GRP = #{pump_grp}
GROUP BY cppi.PUMP_IDX, rd_pmb.TAGNAME, rd_spi.TAGNAME;

SELECT cppi.PUMP_IDX, cppi.PUMP_GRP, cppi.PUMP_GRP_NM, cppi.PUMP_NM, rd_pmb.TAGNAME AS PMB_TAGNAME, rd_pri.TAGNAME AS PRI_TAGNAME, MAX(rd_pmb.ts) AS PMB_TS, MAX(rd_pri.ts) AS PRI_TS, rd_pmb.value as PMB_VALUE, CASE WHEN rd_pmb.value = 1 THEN "On" ELSE "Off" END AS PUMP_YN, ROUND(rd_pri.value, 2) AS 'PRI' FROM TB_CTR_PRF_PUMPMST_INF cppi LEFT JOIN TB_RAWDATA rd_pmb ON cppi.PMB_TAG = rd_pmb.TAGNAME AND rd_pmb.TS > DATE_SUB(NOW(), INTERVAL 10 MINUTE) AND rd_pmb.TS <= DATE_ADD(NOW(), INTERVAL 10 MINUTE) LEFT JOIN TB_RAWDATA rd_pri ON cppi.PRI_T_TAG = rd_pri.TAGNAME AND rd_pri.TS > DATE_SUB(NOW(), INTERVAL 10 MINUTE) AND rd_pri.TS <= DATE_ADD(NOW(), INTERVAL 10 MINUTE) WHERE cppi.USE_YN = 1
and cppi.PUMP_GRP = #{pump_grp}
GROUP BY cppi.PUMP_IDX, rd_pmb.TAGNAME, rd_pri.TAGNAME;

