UPDATE
TB_AI_MODE_RST
SET PRE_PUMP = #{PRE_PUMP}, IS_WORK = #{IS_WORK}
where RGSTR_TIME = #{NOW_DATE} and PUMP_GRP = #{PUMP_GRP}
